def is_prime(n):
    # check if a number is prime
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def is_palindrome(n):
    # check if a number is palindrome
    return str(n) == str(n)[::-1]

def check_number(n):
    # check if a number is both palindrome and prime
    return is_palindrome(n) and is_prime(n)

num = int(input("Enter a number: "))
if check_number(num):
    print(f"{num} is both a palindrome and a prime number.")
else:
    print(f"{num} is either not a palindrome or not a prime number.")
```

